echo -e "\n--- Thermal Zones ---"; for t in /sys/class/thermal/thermal_zone*; do echo -n "$(cat $t/type 2>/dev/null): "; cat $t/temp 2>/dev/null | awk '{printf "%.1f°C\n", $1/1000}'; done; echo -e "\n--- HWMonitors ---"; for h in /sys/class/hwmon/hwmon*; do name=$(cat $h/name 2>/dev/null); for t in $h/temp*_input; do [ -f "$t" ] && echo -n "$name ($(basename $t)): " && cat $t 2>/dev/null | awk '{printf "%.1f°C\n", $1/1000}'; done; done 2>/dev/null
